// -R- Animated text field -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R
type FieldProps = {
  id: string; label: string; required?: boolean; type?: string;
  placeholder: string; value: string;
  onChange: (v: string) => void;
  error?: string; disabled?: boolean;
  rows?: number; maxLength?: number; charCount?: number;
};

const Field = memo(function Field({
  id, label, required, type = "text", placeholder, value, onChange,
  error, disabled, rows, maxLength, charCount,
}: FieldProps) {
  const [focused, setFocused] = useState(false);
  const [draft, setDraft] = useState(value);
  const hasValue = draft.length > 0;

  useEffect(() => {
    setDraft(value);
  }, [value]);

  const handleFocus = useCallback(() => setFocused(true), []);
  const handleBlur = useCallback(() => setFocused(false), []);
  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const next = e.target.value;
    setDraft(next);
    onChange(next);
  }, [onChange]);

  const baseClass = `
    block box-border w-full min-w-0 px-4 pt-7 pb-1.5 rounded-xl border bg-background text-foreground text-sm leading-5
    focus:outline-none transition-[border-color,box-shadow,background-color,color] duration-200 disabled:opacity-60 resize-none
    ${error ? "border-red-400 focus:ring-2 focus:ring-red-400/30"
      : focused ? "border-primary ring-2 ring-primary/20"
      : "border-border hover:border-primary/40"}
  `;
  const fieldClass = `${baseClass} ${rows ? "h-40 min-h-40 max-h-40" : "h-14 min-h-14 max-h-14"}`;
  const labelRaised = focused || hasValue;

  const shared = {
    id, value: draft, disabled,
    onFocus: handleFocus,
    onBlur: handleBlur,
    onChange: handleChange,
    placeholder: focused ? placeholder : "",
    className: fieldClass,
  };

  return (
    <div className="relative">
      {/* Floating label */}
      <label
        htmlFor={id}
        className={`absolute left-4 pointer-events-none z-10 origin-left font-semibold leading-none transition-[top,font-size,color] duration-200 ${
          labelRaised
            ? `top-2 text-[11px] ${focused ? "text-primary" : "text-muted-foreground"}`
            : "top-4 text-sm text-muted-foreground"
        }`}
      >
        {label}{required && <span className="text-red-500 ml-0.5">*</span>}
      </label>

      {rows ? (
        <textarea {...shared} rows={rows} maxLength={maxLength} />
      ) : (
        <input {...shared} type={type} maxLength={maxLength} />
      )}

      {/* Char count */}
      {charCount !== undefined && (
        <span className="absolute bottom-2.5 right-3.5 text-[10px] text-muted-foreground/50 tabular-nums">
          {draft.length}/{charCount}
        </span>
      )}
      {/* Error */}
      <AnimatePresence>
        {error && (
          <motion.p key="err"
            initial={{ opacity: 0, y: -4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -4 }}
            transition={{ duration: 0.2 }}
            className="flex items-center gap-1 text-xs text-red-500 mt-1.5"
          >
            <AlertCircle className="w-3 h-3" />{error}
          </motion.p>
        )}
      </AnimatePresence>
    </div>
  );
});

